func (m *Model) handleCreatePathMode(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
	keys := ui.DefaultKeyMap

	switch {
	case key.Matches(msg, keys.Cancel):
		m.mode = ModeNormal
		m.pendingSessionName = ""
		m.pathInput.Blur()
