func ParseInitialView(view string) Mode {
	switch strings.ToLower(view) {
	case "bookmarks":
		return ModeBookmarks
	case "projects":
		return ModePickDirectory
	case "clone":
		return ModeCloneChoice
	default:
		return ModeNormal
	}
